import React from "react";

const About = () => (
  <section id="about" className="py-20 px-6 bg-purple-50 dark:bg-gray-900">
    <h2 data-aos="fade-right" className="text-3xl font-bold text-center mb-8">About Me</h2>
    <p data-aos="fade-left" className="text-lg text-gray-700 dark:text-gray-200 leading-relaxed text-center max-w-3xl mx-auto">
      I’m Hetvi Prajapati, a Computer Science student with hands-on experience in full-stack development, cloud computing, and software engineering.
      I enjoy building applications that solve real-world problems and continuously learning modern technologies.
    </p>
  </section>
);

export default About;
